INSERT INTO questions (id, subject_id, topic_id, difficulty, question_text, option_a, option_b, option_c, option_d, correct_answer, solution) VALUES
('a2000001-0000-0000-0000-000000000001', 'a1111111-1111-1111-1111-111111111111', 'a1111111-1111-1111-1111-111111111112', 'EASY', 'A body of mass 5 kg is acted upon by a force that changes its velocity from 4 m/s to 10 m/s in 2 seconds. What is the force applied?', '10 N', '15 N', '20 N', '25 N', 'B', 'F = m(v-u)/t = 5*(10-4)/2 = 15 N'),
('a2000001-0000-0000-0000-000000000002', 'a1111111-1111-1111-1111-111111111111', 'a1111111-1111-1111-1111-111111111112', 'EASY', 'Newton''s third law states that action and reaction forces are:', 'Equal in magnitude, same direction', 'Equal in magnitude, opposite direction', 'Unequal, same direction', 'Unequal, opposite direction', 'B', 'Action and reaction are equal and opposite but act on different bodies.'),
('a2000001-0000-0000-0000-000000000003', 'a1111111-1111-1111-1111-111111111111', 'a1111111-1111-1111-1111-111111111112', 'EASY', 'A 2 kg block slides on a surface with coefficient of kinetic friction 0.4. Find the friction force. (g=10 m/s^2)', '4 N', '8 N', '10 N', '12 N', 'B', 'f = mumg = 0.4*2*10 = 8 N'),
('a2000001-0000-0000-0000-000000000004', 'a1111111-1111-1111-1111-111111111111', 'a1111111-1111-1111-1111-111111111112', 'EASY', 'The law of conservation of momentum applies when:', 'Net external force is zero', 'Net internal force is zero', 'Both forces are zero', 'Friction is absent', 'A', 'Momentum is conserved when no net external force acts on the system.'),
('a2000001-0000-0000-0000-000000000005', 'a1111111-1111-1111-1111-111111111111', 'a1111111-1111-1111-1111-111111111112', 'EASY', 'A ball of mass 0.5 kg moving at 6 m/s collides and comes to rest. Impulse imparted is:', '2 N s', '3 N s', '4 N s', '6 N s', 'B', 'Impulse = change in momentum = 0.5*6 = 3 N s'),
('a2000001-0000-0000-0000-000000000006', 'a1111111-1111-1111-1111-111111111111', 'a1111111-1111-1111-1111-111111111112', 'EASY', 'The gravitational force between two masses is 40 N. If distance is doubled, new force is:', '10 N', '20 N', '40 N', '80 N', 'A', 'F 1/r^2, doubling distance -> force becomes F/4 = 10 N'),
('a2000001-0000-0000-0000-000000000007', 'a1111111-1111-1111-1111-111111111111', 'a1111111-1111-1111-1111-111111111112', 'EASY', 'Escape velocity from Earth''s surface is approximately:', '7.9 km/s', '11.2 km/s', '16.5 km/s', '9.8 km/s', 'B', 'Escape velocity = sqrt(2gR) ~= 11.2 km/s'),
('a2000001-0000-0000-0000-000000000008', 'a1111111-1111-1111-1111-111111111111', 'a1111111-1111-1111-1111-111111111112', 'MEDIUM', 'A body in a geostationary orbit has a time period of:', '12 hours', '24 hours', '48 hours', '72 hours', 'B', 'Geostationary orbit has period equal to Earth''s rotation = 24 hours.'),
('a2000001-0000-0000-0000-000000000009', 'a1111111-1111-1111-1111-111111111111', 'a1111111-1111-1111-1111-111111111112', 'MEDIUM', 'Two bodies of masses 3 kg and 5 kg collide elastically. Before collision 3 kg moves at 4 m/s and 5 kg is at rest. Velocity of 3 kg after collision:', '-0.5 m/s', '0.5 m/s', '-1 m/s', '1 m/s', 'C', 'For elastic collision: v1 = (m1-m2)u1/(m1+m2) = (3-5)*4/8 = -1 m/s.'),
('a2000001-0000-0000-0000-000000000010', 'a1111111-1111-1111-1111-111111111111', 'a1111111-1111-1111-1111-111111111112', 'MEDIUM', 'Kepler''s second law (law of areas) is a consequence of conservation of:', 'Energy', 'Linear Momentum', 'Angular Momentum', 'Mass', 'C', 'The equal areas in equal times arises from conservation of angular momentum.'),
('a2000001-0000-0000-0000-000000000011', 'a1111111-1111-1111-1111-111111111111', 'a1111111-1111-1111-1111-111111111112', 'MEDIUM', 'A rocket ejects gas at 500 m/s at rate 2 kg/s. Thrust force is:', '250 N', '500 N', '1000 N', '2000 N', 'C', 'Thrust = v * dm/dt = 500*2 = 1000 N'),
('a2000001-0000-0000-0000-000000000012', 'a1111111-1111-1111-1111-111111111111', 'a1111111-1111-1111-1111-111111111112', 'MEDIUM', 'The orbital velocity of a satellite at height h above Earth of radius R is:', 'sqrt(gR)', 'sqrt(gR^2/(R+h))', 'sqrt(g(R+h))', 'gR/(R+h)', 'B', 'v = sqrt(GM/(R+h)) = sqrt(gR^2/(R+h))'),
('a2000001-0000-0000-0000-000000000013', 'a1111111-1111-1111-1111-111111111111', 'a1111111-1111-1111-1111-111111111112', 'MEDIUM', 'A person weighs 600 N on Earth. Weight on moon (g_moon = g/6) is:', '50 N', '100 N', '200 N', '600 N', 'B', 'W_moon = mg/6 = 600/6 = 100 N'),
('a2000001-0000-0000-0000-000000000014', 'a1111111-1111-1111-1111-111111111111', 'a1111111-1111-1111-1111-111111111112', 'MEDIUM', 'Work done by friction on a body sliding on a rough surface is always:', 'Positive', 'Negative', 'Zero', 'Depends on surface', 'B', 'Friction opposes motion, so work done is always negative.'),
('a2000001-0000-0000-0000-000000000015', 'a1111111-1111-1111-1111-111111111111', 'a1111111-1111-1111-1111-111111111112', 'HARD', 'If binding energy of a satellite is E, what is total energy?', '-E', 'E', '-2E', '2E', 'A', 'Total energy = -BE = -E for a bound satellite.'),
('a2000001-0000-0000-0000-000000000016', 'a1111111-1111-1111-1111-111111111111', 'a1111111-1111-1111-1111-111111111112', 'HARD', 'A mass m is on a frictionless incline of angle theta. The normal force is:', 'mg', 'mg sintheta', 'mg costheta', 'mg tantheta', 'C', 'N = mg costheta on a frictionless incline.')
INSERT INTO questions (id, subject_id, topic_id, difficulty, question_text, option_a, option_b, option_c, option_d, correct_answer, solution) VALUES
('a2000002-0000-0000-0000-000000000001', 'a1111111-1111-1111-1111-111111111111', 'a1111111-1111-1111-1111-111111111113', 'EASY', 'Moment of inertia of a solid sphere about its diameter is:', '(2/5)MR^2', '(1/2)MR^2', '(2/3)MR^2', 'MR^2', 'A', 'I = (2/5)MR^2 for solid sphere about diameter.'),
('a2000002-0000-0000-0000-000000000002', 'a1111111-1111-1111-1111-111111111111', 'a1111111-1111-1111-1111-111111111113', 'EASY', 'Angular momentum L = Iomega. If I doubles and omega halves, L:', 'Doubles', 'Halves', 'Remains same', 'Quadruples', 'C', 'L = Iomega = (2I)(omega/2) = Iomega, unchanged.'),
('a2000002-0000-0000-0000-000000000003', 'a1111111-1111-1111-1111-111111111111', 'a1111111-1111-1111-1111-111111111113', 'EASY', 'Torque is defined as:', 'F * r', 'r * F', 'F / r', 'F r', 'B', 'Torque tau = r * F (cross product).'),
('a2000002-0000-0000-0000-000000000004', 'a1111111-1111-1111-1111-111111111111', 'a1111111-1111-1111-1111-111111111113', 'EASY', 'A body rolling without slipping on a surface has:', 'Only translational KE', 'Only rotational KE', 'Both translational and rotational KE', 'Neither', 'C', 'Rolling body has both translational and rotational kinetic energy.'),
('a2000002-0000-0000-0000-000000000005', 'a1111111-1111-1111-1111-111111111111', 'a1111111-1111-1111-1111-111111111113', 'EASY', 'Radius of gyration k is related to moment of inertia I and mass M by:', 'I = Mk', 'I = Mk^2', 'I = M/k^2', 'I = M^2k', 'B', 'I = Mk^2 where k is radius of gyration.'),
('a2000002-0000-0000-0000-000000000006', 'a1111111-1111-1111-1111-111111111111', 'a1111111-1111-1111-1111-111111111113', 'EASY', 'Perpendicular axis theorem applies to:', '3D bodies', '2D laminar bodies only', 'Spherical bodies', 'None', 'B', 'Perpendicular axis theorem: Iz = Ix + Iy, applies to flat 2D laminas.'),
('a2000002-0000-0000-0000-000000000007', 'a1111111-1111-1111-1111-111111111111', 'a1111111-1111-1111-1111-111111111113', 'EASY', 'A disc of mass M and radius R has moment of inertia about central axis:', 'MR^2', '(1/2)MR^2', '(2/3)MR^2', '(2/5)MR^2', 'B', 'I = (1/2)MR^2 for solid disc about central axis.'),
('a2000002-0000-0000-0000-000000000008', 'a1111111-1111-1111-1111-111111111111', 'a1111111-1111-1111-1111-111111111113', 'MEDIUM', 'A torque of 10 N m acts on a body with I = 2 kg m^2. Angular acceleration is:', '2 rad/s^2', '5 rad/s^2', '10 rad/s^2', '20 rad/s^2', 'B', 'alpha = tau/I = 10/2 = 5 rad/s^2.'),
('a2000002-0000-0000-0000-000000000009', 'a1111111-1111-1111-1111-111111111111', 'a1111111-1111-1111-1111-111111111113', 'MEDIUM', 'A skater pulls in arms and spins faster. This demonstrates conservation of:', 'Energy', 'Linear momentum', 'Angular momentum', 'Torque', 'C', 'No external torque, so angular momentum is conserved.'),
('a2000002-0000-0000-0000-000000000010', 'a1111111-1111-1111-1111-111111111111', 'a1111111-1111-1111-1111-111111111113', 'MEDIUM', 'Kinetic energy of rotation is:', '(1/2)Iomega', '(1/2)Iomega^2', 'Iomega^2', '(1/2)mv^2', 'B', 'KE_rot = (1/2)Iomega^2.'),
('a2000002-0000-0000-0000-000000000011', 'a1111111-1111-1111-1111-111111111111', 'a1111111-1111-1111-1111-111111111113', 'MEDIUM', 'A solid cylinder rolls down an incline. Fraction of KE that is rotational:', '1/2', '1/3', '2/3', '1/4', 'B', 'For cylinder: KE_rot/KE_total = (1/2)/(1+1) = 1/3.'),
('a2000002-0000-0000-0000-000000000012', 'a1111111-1111-1111-1111-111111111111', 'a1111111-1111-1111-1111-111111111113', 'MEDIUM', 'MI of a hollow cylinder about its axis is:', '(1/2)MR^2', 'MR^2', '(2/3)MR^2', '(2/5)MR^2', 'B', 'I = MR^2 for hollow cylinder (all mass at radius R).'),
('a2000002-0000-0000-0000-000000000013', 'a1111111-1111-1111-1111-111111111111', 'a1111111-1111-1111-1111-111111111113', 'MEDIUM', 'Angular impulse equals:', 'Change in torque', 'Change in angular momentum', 'Change in angular velocity', 'Torque * angular velocity', 'B', 'Angular impulse = DeltaL = change in angular momentum.'),
('a2000002-0000-0000-0000-000000000015', 'a1111111-1111-1111-1111-111111111111', 'a1111111-1111-1111-1111-111111111113', 'HARD', 'A body of I = 0.5 kg m^2 is rotating at 4 rad/s. Its angular momentum is:', '1 kg m^2/s', '2 kg m^2/s', '4 kg m^2/s', '8 kg m^2/s', 'B', 'L = Iomega = 0.5*4 = 2 kg m^2/s.'),
('a2000002-0000-0000-0000-000000000016', 'a1111111-1111-1111-1111-111111111111', 'a1111111-1111-1111-1111-111111111113', 'HARD', 'A disc of I = 1 kg m^2 starts from rest under torque 2 N m. After 3 s, angular velocity:', '2 rad/s', '4 rad/s', '6 rad/s', '8 rad/s', 'C', 'alpha = tau/I = 2. omega = alphat = 2*3 = 6 rad/s.'),
('a2000002-0000-0000-0000-000000000017', 'a1111111-1111-1111-1111-111111111111', 'a1111111-1111-1111-1111-111111111113', 'HARD', 'Parallel axis theorem: I = Icm + Md^2. If Icm = 2 kg m^2, M=5 kg, d=2 m:', '10 kg m^2', '12 kg m^2', '20 kg m^2', '22 kg m^2', 'D', 'I = 2 + 5*4 = 22 kg m^2.'),
('a2000002-0000-0000-0000-000000000018', 'a1111111-1111-1111-1111-111111111111', 'a1111111-1111-1111-1111-111111111113', 'HARD', 'The condition for a rigid body to be in equilibrium is:', 'SigmaF=0 only', 'Sigmatau=0 only', 'SigmaF=0 and Sigmatau=0', 'SigmaF=Sigmatau', 'C', 'Both translational (SigmaF=0) and rotational (Sigmatau=0) equilibrium required.'),
('a2000002-0000-0000-0000-000000000019', 'a1111111-1111-1111-1111-111111111111', 'a1111111-1111-1111-1111-111111111113', 'HARD', 'A hollow sphere has MI = (2/3)MR^2. Compared to solid sphere (2/5)MR^2), hollow sphere MI is:', 'Less', 'Equal', 'Greater', 'Cannot compare', 'C', '2/3 > 2/5, so hollow sphere has greater MI (mass farther from axis).'),
('a2000002-0000-0000-0000-000000000020', 'a1111111-1111-1111-1111-111111111111', 'a1111111-1111-1111-1111-111111111113', 'HARD', 'In rolling without slipping, the velocity of contact point with ground is:', '2v', 'v', 'v/2', 'Zero', 'D', 'Contact point is instantaneously at rest in rolling without slipping.')
INSERT INTO questions (id, subject_id, topic_id, difficulty, question_text, option_a, option_b, option_c, option_d, correct_answer, solution) VALUES
('a2000003-0000-0000-0000-000000000001', 'a1111111-1111-1111-1111-111111111111', 'a1111111-1111-1111-1111-111111111114', 'EASY', 'Time period of a simple pendulum depends on:', 'Mass of bob', 'Length and g', 'Amplitude', 'All of these', 'B', 'T = 2pisqrt(L/g), depends only on length and g.')
INSERT INTO questions (id, subject_id, topic_id, difficulty, question_text, option_a, option_b, option_c, option_d, correct_answer, solution) VALUES
('a2000005-0000-0000-0000-000000000001', 'a1111111-1111-1111-1111-111111111111', 'a1111111-1111-1111-1111-111111111116', 'EASY', 'Coulomb''s law gives force between two charges as:', 'F = kq1q2/r', 'F = kq1q2/r^2', 'F = q1q2/r^2', 'F = kq1/q2r^2', 'B', 'Coulomb: F = kq1q2/r^2.'),
('a2000005-0000-0000-0000-000000000002', 'a1111111-1111-1111-1111-111111111111', 'a1111111-1111-1111-1111-111111111116', 'EASY', 'Electric field due to a point charge at distance r is:', 'kQ/r', 'kQ/r^2', 'kQ^2/r', 'kQ/r^3', 'B', 'E = kQ/r^2.'),
('a2000005-0000-0000-0000-000000000003', 'a1111111-1111-1111-1111-111111111111', 'a1111111-1111-1111-1111-111111111116', 'EASY', 'Electric potential at a point is defined as work done per unit __ charge:', 'Positive', 'Negative', 'Test', 'Moving', 'C', 'V = W/q_0 where q_0 is positive test charge.'),
('a2000005-0000-0000-0000-000000000004', 'a1111111-1111-1111-1111-111111111111', 'a1111111-1111-1111-1111-111111111116', 'EASY', 'Inside a conductor in electrostatic equilibrium, electric field is:', 'Maximum', 'Minimum', 'Zero', 'Uniform', 'C', 'E = 0 inside a conductor in electrostatic equilibrium.')
INSERT INTO questions (id, subject_id, topic_id, difficulty, question_text, option_a, option_b, option_c, option_d, correct_answer, solution) VALUES
('b3000001-0000-0000-0000-000000000001', 'b2222222-2222-2222-2222-222222222222', 'b2222222-2222-2222-2222-222222222201', 'EASY', 'Molar mass of water (H_2O) is:', '16 g/mol', '18 g/mol', '20 g/mol', '32 g/mol', 'B', 'H_2O: 2*1 + 16 = 18 g/mol.'),
('b3000001-0000-0000-0000-000000000002', 'b2222222-2222-2222-2222-222222222222', 'b2222222-2222-2222-2222-222222222201', 'EASY', 'Avogadro''s number is approximately:', '6.022*10^2^2', '6.022*10^2^3', '6.022*10^2^4', '6.022*10^2^1', 'B', 'Avogadro number NA = 6.022*10^2^3 mol-^1.'),
('b3000001-0000-0000-0000-000000000003', 'b2222222-2222-2222-2222-222222222222', 'b2222222-2222-2222-2222-222222222201', 'EASY', 'The number of moles in 44 g of CO_2 (molar mass 44 g/mol) is:', '0.5', '1', '2', '44', 'B', 'n = mass/molar mass = 44/44 = 1 mol.'),
('b3000001-0000-0000-0000-000000000004', 'b2222222-2222-2222-2222-222222222222', 'b2222222-2222-2222-2222-222222222201', 'EASY', 'Law of conservation of mass states:', 'Mass can be created', 'Mass can be destroyed', 'Total mass of reactants = products', 'Mass varies with temperature', 'C', 'Total mass is conserved in chemical reactions.'),
('b3000001-0000-0000-0000-000000000005', 'b2222222-2222-2222-2222-222222222222', 'b2222222-2222-2222-2222-222222222201', 'EASY', 'Empirical formula represents:', 'Molecular structure', 'Simplest whole number ratio of atoms', 'Actual number of atoms', '3D arrangement', 'B', 'Empirical formula = simplest ratio of atoms in compound.'),
('b3000001-0000-0000-0000-000000000006', 'b2222222-2222-2222-2222-222222222222', 'b2222222-2222-2222-2222-222222222201', 'EASY', 'Molarity is defined as:', 'Moles per litre of solution', 'Moles per kg of solvent', 'Mass per litre', 'Moles per mole solvent', 'A', 'Molarity M = moles of solute / volume of solution in litres.'),
('b3000001-0000-0000-0000-000000000007', 'b2222222-2222-2222-2222-222222222222', 'b2222222-2222-2222-2222-222222222201', 'EASY', 'Volume of 1 mole of any gas at STP is:', '11.2 L', '22.4 L', '44.8 L', '5.6 L', 'B', 'Molar volume at STP = 22.4 L/mol.'),
('b3000001-0000-0000-0000-000000000008', 'b2222222-2222-2222-2222-222222222222', 'b2222222-2222-2222-2222-222222222201', 'MEDIUM', 'Percentage composition of carbon in CO_2 is approximately:', '27.3%', '36.4%', '50%', '72.7%', 'A', '%C = (12/44)*100 = 27.27%.'),
('b3000001-0000-0000-0000-000000000009', 'b2222222-2222-2222-2222-222222222222', 'b2222222-2222-2222-2222-222222222201', 'MEDIUM', 'Dalton''s atomic theory states atoms of same element are:', 'Different in all properties', 'Identical in mass and properties', 'Always charged', 'Divisible', 'B', 'Dalton: atoms of same element are identical in mass and chemical properties.'),
('b3000001-0000-0000-0000-000000000010', 'b2222222-2222-2222-2222-222222222222', 'b2222222-2222-2222-2222-222222222201', 'MEDIUM', 'Molality is moles of solute per:', 'Litre of solution', '100 g of solvent', 'Kg of solvent', 'Kg of solution', 'C', 'Molality m = moles solute / kg of solvent.'),
('b3000001-0000-0000-0000-000000000011', 'b2222222-2222-2222-2222-222222222222', 'b2222222-2222-2222-2222-222222222201', 'MEDIUM', 'Law of definite proportions was given by:', 'Dalton', 'Proust', 'Lavoisier', 'Avogadro', 'B', 'Proust''s law: compounds always contain elements in fixed mass ratio.'),
('b3000001-0000-0000-0000-000000000012', 'b2222222-2222-2222-2222-222222222222', 'b2222222-2222-2222-2222-222222222201', 'MEDIUM', 'How many molecules are in 2 mol of N_2?', '6.022*10^2^3', '12.044*10^2^3', '3.011*10^2^3', '2.408*10^2^3', 'B', '2 mol * 6.022*10^2^3 = 12.044*10^2^3 molecules.'),
('b3000001-0000-0000-0000-000000000013', 'b2222222-2222-2222-2222-222222222222', 'b2222222-2222-2222-2222-222222222201', 'MEDIUM', 'Limiting reagent in a reaction is the one that:', 'Is in excess', 'Determines amount of product', 'Has least molar mass', 'Reacts slowest', 'B', 'Limiting reagent is fully consumed and determines max product formed.'),
('b3000001-0000-0000-0000-000000000014', 'b2222222-2222-2222-2222-222222222222', 'b2222222-2222-2222-2222-222222222201', 'MEDIUM', 'Molecular formula of glucose is C H_1_2O . Its empirical formula is:', 'C_2H O_2', 'CH_2O', 'C_3H O_3', 'C H_1_2O', 'B', 'Simplest ratio: C:H:O = 6:12:6 = 1:2:1 -> CH_2O.'),
('b3000001-0000-0000-0000-000000000015', 'b2222222-2222-2222-2222-222222222222', 'b2222222-2222-2222-2222-222222222201', 'HARD', 'Mole fraction of A in a solution of 2 mol A and 8 mol B:', '0.2', '0.8', '0.25', '0.4', 'A', 'A = nA/(nA+nB) = 2/10 = 0.2.'),
('b3000001-0000-0000-0000-000000000016', 'b2222222-2222-2222-2222-222222222222', 'b2222222-2222-2222-2222-222222222201', 'HARD', 'A compound has 40% C, 6.7% H, 53.3% O by mass. Empirical formula:', 'CH_2O', 'C_2H O', 'CH O', 'CHO', 'A', 'C:H:O = 40/12 : 6.7/1 : 53.3/16 = 3.33:6.7:3.33 = 1:2:1 -> CH_2O.'),
('b3000001-0000-0000-0000-000000000018', 'b2222222-2222-2222-2222-222222222222', 'b2222222-2222-2222-2222-222222222201', 'HARD', 'If reaction yield is 80% and theoretical yield is 25 g, actual yield is:', '20 g', '31.25 g', '15 g', '10 g', 'A', 'Actual yield = 0.80 * 25 = 20 g.'),
('b3000001-0000-0000-0000-000000000019', 'b2222222-2222-2222-2222-222222222222', 'b2222222-2222-2222-2222-222222222201', 'HARD', 'Gay-Lussac''s law of combining volumes applies to:', 'Solids', 'Liquids', 'Gases only', 'All states', 'C', 'Gay-Lussac: volumes of gaseous reactants/products are in simple whole number ratios.'),
('b3000001-0000-0000-0000-000000000020', 'b2222222-2222-2222-2222-222222222222', 'b2222222-2222-2222-2222-222222222201', 'HARD', 'The ppm (parts per million) concentration means mg of solute per:', 'mL solution', 'g solution', 'kg solution', 'L solution', 'C', '1 ppm = 1 mg/kg = 1 mg per kg of solution.')
INSERT INTO questions (id, subject_id, topic_id, difficulty, question_text, option_a, option_b, option_c, option_d, correct_answer, solution) VALUES
('b3000002-0000-0000-0000-000000000001', 'b2222222-2222-2222-2222-222222222222', 'b2222222-2222-2222-2222-222222222202', 'EASY', 'The charge on an electron is:', '+1.6*10-^1^9 C', '-1.6*10-^1^9 C', '1.6*10-^2^7 C', 'None', 'B', 'Electron charge = -1.6*10-^1^9 C.'),
('b3000002-0000-0000-0000-000000000002', 'b2222222-2222-2222-2222-222222222222', 'b2222222-2222-2222-2222-222222222202', 'EASY', 'Atomic number of an element is equal to number of:', 'Neutrons', 'Protons', 'Electrons and neutrons', 'Protons and neutrons', 'B', 'Atomic number Z = number of protons.'),
