('b3000002-0000-0000-0000-000000000004', 'b2222222-2222-2222-2222-222222222222', 'b2222222-2222-2222-2222-222222222202', 'EASY', 'Maximum number of electrons in n=2 shell is:', '2', '8', '18', '32', 'B', '2n^2 = 2*4 = 8 electrons in n=2.'),
('b3000002-0000-0000-0000-000000000005', 'b2222222-2222-2222-2222-222222222222', 'b2222222-2222-2222-2222-222222222202', 'EASY', 'Aufbau principle states electrons fill orbitals in order of:', 'Decreasing energy', 'Increasing energy', 'Increasing mass', 'Alphabetical order', 'B', 'Aufbau: electrons fill lowest energy orbitals first.'),
