INSERT INTO questions (id, subject_id, topic_id, difficulty, question_text, option_a, option_b, option_c, option_d, correct_answer, solution) VALUES
('b3000005-0000-0000-0000-000000000001', 'b2222222-2222-2222-2222-222222222222', 'b2222222-2222-2222-2222-222222222205', 'EASY', 'At equilibrium, rate of forward reaction equals rate of:', 'Backward reaction', 'Dissociation', 'Ionization', 'None', 'A', 'Dynamic equilibrium: forward rate = backward rate.'),
('b3000005-0000-0000-0000-000000000002', 'b2222222-2222-2222-2222-222222222222', 'b2222222-2222-2222-2222-222222222205', 'EASY', 'Le Chatelier''s principle states that if a system at equilibrium is disturbed, it will:', 'Reach new equilibrium faster', 'Shift to counteract the disturbance', 'Stop reacting', 'Change temperature', 'B', 'Le Chatelier: system shifts to minimize the effect of the disturbance.'),
('b3000005-0000-0000-0000-000000000003', 'b2222222-2222-2222-2222-222222222222', 'b2222222-2222-2222-2222-222222222205', 'EASY', 'For N_2 + 3H_2 2NH_3, increasing pressure favors:', 'Reactant side', 'Product side (less moles)', 'No change', 'Cannot determine', 'B', 'Increased pressure favors side with fewer moles of gas (products: 2 mol).'),
('b3000005-0000-0000-0000-000000000004', 'b2222222-2222-2222-2222-222222222222', 'b2222222-2222-2222-2222-222222222205', 'EASY', 'pH of a neutral solution at 25 degreesC is:', '0', '7', '14', '1', 'B', 'Neutral solution: [H+] = 10-^7 M -> pH = 7.'),
