INSERT INTO questions (id, subject_id, topic_id, difficulty, question_text, option_a, option_b, option_c, option_d, correct_answer, solution) VALUES
('c4000006-0000-0000-0000-000000000001', 'c3333333-3333-3333-3333-333333333333', 'c3333333-3333-3333-3333-333333333306', 'EASY', 'lim(x->0) sinx/x = ?', '0', '1', 'infinity', 'Does not exist', 'B', 'Standard limit: lim(x->0) sinx/x = 1.'),
('c4000006-0000-0000-0000-000000000002', 'c3333333-3333-3333-3333-333333333333', 'c3333333-3333-3333-3333-333333333306', 'EASY', 'd/dx(x ) = ?', 'nx -^1', 'x -^1', 'nx', '(n-1)x', 'A', 'Power rule: d/dx(x ) = nx -^1.'),
('c4000006-0000-0000-0000-000000000003', 'c3333333-3333-3333-3333-333333333333', 'c3333333-3333-3333-3333-333333333306', 'EASY', 'd/dx(sinx) = ?', 'cosx', '-cosx', 'sinx', '-sinx', 'A', 'd/dx(sinx) = cosx.'),
('c4000006-0000-0000-0000-000000000004', 'c3333333-3333-3333-3333-333333333333', 'c3333333-3333-3333-3333-333333333306', 'EASY', 'd/dx(e ) = ?', 'e -^1', 'xe', 'e', 'e', 'C', 'd/dx(e ) = e .'),
('c4000006-0000-0000-0000-000000000005', 'c3333333-3333-3333-3333-333333333333', 'c3333333-3333-3333-3333-333333333306', 'EASY', 'd/dx(ln x) = ?', '1', '1/x', 'x', 'ln x', 'B', 'd/dx(ln x) = 1/x.'),
('c4000006-0000-0000-0000-000000000006', 'c3333333-3333-3333-3333-333333333333', 'c3333333-3333-3333-3333-333333333306', 'EASY', 'A function f(x) is continuous at x=a if lim(x->a) f(x) equals:', '0', '1', 'f(a)', 'f(0)', 'C', 'Continuity: lim(x->a)f(x) = f(a).'),
('c4000006-0000-0000-0000-000000000007', 'c3333333-3333-3333-3333-333333333333', 'c3333333-3333-3333-3333-333333333306', 'EASY', 'd/dx(cosx) = ?', 'sinx', '-sinx', 'cosx', '-cosx', 'B', 'd/dx(cosx) = -sinx.'),
('c4000006-0000-0000-0000-000000000008', 'c3333333-3333-3333-3333-333333333333', 'c3333333-3333-3333-3333-333333333306', 'MEDIUM', 'Chain rule: d/dx[f(g(x))] = ?', 'f''(x)g''(x)', 'f''(g(x)) g''(x)', 'f(g''(x))', 'f''(x)+g''(x)', 'B', 'Chain rule: derivative of outer * derivative of inner.')
INSERT INTO questions (id, subject_id, topic_id, difficulty, question_text, option_a, option_b, option_c, option_d, correct_answer, solution) VALUES
('c4000008-0000-0000-0000-000000000001', 'c3333333-3333-3333-3333-333333333333', 'c3333333-3333-3333-3333-333333333308', 'EASY', 'x dx = ?', 'x +^1/(n+1) + C', 'x /n + C', 'nx -^1 + C', 'x +^1 + C', 'A', 'x dx = x +^1/(n+1) + C (n != -1).'),
('c4000008-0000-0000-0000-000000000002', 'c3333333-3333-3333-3333-333333333333', 'c3333333-3333-3333-3333-333333333308', 'EASY', 'e dx = ?', 'e -^1 + C', 'e + C', 'xe + C', 'e + C', 'B', 'e dx = e + C.'),
('c4000008-0000-0000-0000-000000000003', 'c3333333-3333-3333-3333-333333333333', 'c3333333-3333-3333-3333-333333333308', 'EASY', '(1/x) dx = ?', 'x + C', '1/x + C', 'ln|x| + C', '1/x^2 + C', 'C', '(1/x) dx = ln|x| + C.'),
('c4000008-0000-0000-0000-000000000004', 'c3333333-3333-3333-3333-333333333333', 'c3333333-3333-3333-3333-333333333308', 'EASY', 'sinx dx = ?', 'cosx + C', '-cosx + C', 'sinx + C', '-sinx + C', 'B', 'sinx dx = -cosx + C.'),
('c4000008-0000-0000-0000-000000000005', 'c3333333-3333-3333-3333-333333333333', 'c3333333-3333-3333-3333-333333333308', 'EASY', 'Definite integral _0^1 x dx = ?', '0', '1/2', '1', '2', 'B', '_0^1 x dx = [x^2/2]_0^1 = 1/2.'),
('c4000008-0000-0000-0000-000000000006', 'c3333333-3333-3333-3333-333333333333', 'c3333333-3333-3333-3333-333333333308', 'EASY', 'cosx dx = ?', '-sinx + C', 'sinx + C', 'cosx + C', '-cosx + C', 'B', 'cosx dx = sinx + C.'),
('c4000008-0000-0000-0000-000000000007', 'c3333333-3333-3333-3333-333333333333', 'c3333333-3333-3333-3333-333333333308', 'EASY', 'The order of differential equation d^2y/dx^2 + dy/dx = 0 is:', '1', '2', '3', '0', 'B', 'Order = highest derivative = 2.'),
('c4000008-0000-0000-0000-000000000008', 'c3333333-3333-3333-3333-333333333333', 'c3333333-3333-3333-3333-333333333308', 'MEDIUM', 'sec^2x dx = ?', 'secx tanx + C', 'tanx + C', '-cotx + C', '2secx + C', 'B', 'sec^2x dx = tanx + C.'),
('c4000008-0000-0000-0000-000000000009', 'c3333333-3333-3333-3333-333333333333', 'c3333333-3333-3333-3333-333333333308', 'MEDIUM', '_0^(pi/2) sinx dx = ?', '0', '1', '2', 'pi/2', 'B', '_0^(pi/2) sinx dx = [-cosx]_0^(pi/2) = 0-(-1) = 1.'),
('c4000008-0000-0000-0000-000000000010', 'c3333333-3333-3333-3333-333333333333', 'c3333333-3333-3333-3333-333333333308', 'MEDIUM', 'Integration by parts: u dv = ?', 'uv - v du', 'uv + v du', 'u dv - v du', 'uv', 'A', 'u dv = uv - v du (ILATE rule).'),
('c4000008-0000-0000-0000-000000000011', 'c3333333-3333-3333-3333-333333333333', 'c3333333-3333-3333-3333-333333333308', 'MEDIUM', 'x e dx = ?', 'e (x+1) + C', 'e (x-1) + C', 'xe + C', 'e + C', 'B', 'By parts: u=x, dv=e dx -> xe - e + C = e (x-1) + C.'),
('c4000008-0000-0000-0000-000000000012', 'c3333333-3333-3333-3333-333333333333', 'c3333333-3333-3333-3333-333333333308', 'MEDIUM', 'Variable separable DE: dy/dx = xy can be written as:', 'dy = x dx', 'dy/y = x dx', 'y dy = x dx', 'dy/x = y dx', 'B', 'Separate: dy/y = x dx, then integrate both sides.'),
('c4000008-0000-0000-0000-000000000013', 'c3333333-3333-3333-3333-333333333333', 'c3333333-3333-3333-3333-333333333308', 'MEDIUM', 'Area under curve y=f(x) from x=a to b is:', 'f(x) dx', 'f(x)^2 dx', 'f(b)-f(a)', '[f(b)+f(a)]/2', 'A', 'Area = f(x) dx (for f(x) >= 0).'),
('c4000008-0000-0000-0000-000000000015', 'c3333333-3333-3333-3333-333333333333', 'c3333333-3333-3333-3333-333333333308', 'HARD', '1/(1+x^2) dx = ?', 'tan-^1x + C', 'sin-^1x + C', 'sec-^1x + C', 'ln(1+x^2) + C', 'A', '1/(1+x^2) dx = tan-^1x + C.'),
('c4000008-0000-0000-0000-000000000016', 'c3333333-3333-3333-3333-333333333333', 'c3333333-3333-3333-3333-333333333308', 'HARD', '1/sqrt(1-x^2) dx = ?', 'cos-^1x + C', 'sin-^1x + C', 'tan-^1x + C', '-cos-^1x + C', 'B', '1/sqrt(1-x^2) dx = sin-^1x + C.'),
('c4000008-0000-0000-0000-000000000017', 'c3333333-3333-3333-3333-333333333333', 'c3333333-3333-3333-3333-333333333308', 'HARD', 'Solution of dy/dx = y with y(0)=1 is:', 'y = e', 'y = x+1', 'y = ln x', 'y = cos x', 'A', 'dy/y = dx -> ln y = x + C. y(0)=1 -> C=0 -> y=e .'),
('c4000008-0000-0000-0000-000000000018', 'c3333333-3333-3333-3333-333333333333', 'c3333333-3333-3333-3333-333333333308', 'HARD', 'tan x dx = ?', 'sec^2x + C', 'ln|sec x| + C', '-ln|cos x| + C', 'Both B and C', 'D', 'tanx dx = ln|secx| + C = -ln|cosx| + C (same result).'),
('c4000008-0000-0000-0000-000000000019', 'c3333333-3333-3333-3333-333333333333', 'c3333333-3333-3333-3333-333333333308', 'HARD', 'Fundamental theorem of calculus: d/dx[ f(t)dt] = ?', 'f(a)', 'f(x)', 'F(x)-F(a)', '0', 'B', 'FTC: d/dx[ f(t)dt] = f(x).'),
('c4000008-0000-0000-0000-000000000020', 'c3333333-3333-3333-3333-333333333333', 'c3333333-3333-3333-3333-333333333308', 'HARD', 'Linear DE: dy/dx + P(x)y = Q(x). Integrating factor is:', 'e^ Q dx', 'e^ P dx', 'P(x)', '1/P(x)', 'B', 'IF = e^( P dx). multiply DE by IF to solve.')
INSERT INTO questions (id, subject_id, topic_id, difficulty, question_text, option_a, option_b, option_c, option_d, correct_answer, solution) VALUES
('c4000009-0000-0000-0000-000000000001', 'c3333333-3333-3333-3333-333333333333', 'c3333333-3333-3333-3333-333333333309', 'EASY', 'Order of matrix with 3 rows and 4 columns is:', '4*3', '3*4', '12*1', '1*12', 'B', 'Matrix order = rows * columns = 3*4.')
INSERT INTO questions (id, subject_id, topic_id, difficulty, question_text, option_a, option_b, option_c, option_d, correct_answer, solution) VALUES
('f1110001-0000-0000-0000-000000000001', 'a1111111-1111-1111-1111-111111111111', 'f1110001-0000-0000-0000-000000000001', 'EASY', 'The dimensional formula for force is:', '[MLT-^1]', '[MLT-^2]', '[ML^2T-^2]', '[M^0LT-^2]', 'B', 'F=ma -> [M][LT-^2] = [MLT-^2]'),
('f1110001-0000-0000-0000-000000000002', 'a1111111-1111-1111-1111-111111111111', 'f1110001-0000-0000-0000-000000000001', 'EASY', 'Which of the following is a dimensionless quantity?', 'Strain', 'Stress', 'Pressure', 'Force', 'A', 'Strain = DeltaL/L, ratio of same quantities -> dimensionless'),
('f1110001-0000-0000-0000-000000000003', 'a1111111-1111-1111-1111-111111111111', 'f1110001-0000-0000-0000-000000000001', 'EASY', 'SI unit of luminous intensity is:', 'Candela', 'Lumen', 'Lux', 'Watt', 'A', 'Candela (cd) is the SI base unit of luminous intensity')
INSERT INTO questions (id, subject_id, topic_id, difficulty, question_text, option_a, option_b, option_c, option_d, correct_answer, solution) VALUES
('f1110002-0000-0000-0000-000000000001', 'a1111111-1111-1111-1111-111111111111', 'f1110002-0000-0000-0000-000000000002', 'EASY', 'A projectile is fired at 30 degrees with velocity 20 m/s. Maximum height (g=10):', '5 m', '10 m', '15 m', '20 m', 'A', 'H = u^2sin^2theta/2g = 400*0.25/20 = 5 m'),
('f1110002-0000-0000-0000-000000000003', 'a1111111-1111-1111-1111-111111111111', 'f1110002-0000-0000-0000-000000000002', 'EASY', 'At highest point of projectile, the component of velocity is:', 'Zero', 'Horizontal only', 'Vertical only', 'Both equal', 'B', 'At highest point, vertical velocity = 0. horizontal velocity remains unchanged'),
('f1110002-0000-0000-0000-000000000004', 'a1111111-1111-1111-1111-111111111111', 'f1110002-0000-0000-0000-000000000002', 'EASY', 'A vector of magnitude 5 makes 30 degrees with x-axis. Its x-component is:', '2.5', '5/sqrt2', '5sqrt3/2', '5/2', 'C', 'Ax = A costheta = 5 cos30 degrees = 5*(sqrt3/2) = 5sqrt3/2'),
('f1110002-0000-0000-0000-000000000005', 'a1111111-1111-1111-1111-111111111111', 'f1110002-0000-0000-0000-000000000002', 'EASY', 'Two vectors A and B are perpendicular. The magnitude of A+B is:', 'A+B', 'A-B', 'sqrt(A^2+B^2)', 'A^2+B^2', 'C', '|A+B| = sqrt(A^2+B^2+2AB costheta). theta=90 degrees -> sqrt(A^2+B^2)'),
('f1110002-0000-0000-0000-000000000006', 'a1111111-1111-1111-1111-111111111111', 'f1110002-0000-0000-0000-000000000002', 'MEDIUM', 'Time of flight of a projectile projected at angle theta with velocity u is:', 'u sintheta/g', '2u sintheta/g', 'u costheta/g', '2u costheta/g', 'B', 'T = 2u sintheta/g (time to go up and come back)'),
('f1110002-0000-0000-0000-000000000007', 'a1111111-1111-1111-1111-111111111111', 'f1110002-0000-0000-0000-000000000002', 'MEDIUM', 'A ball is projected horizontally from height 20 m with velocity 10 m/s. Time to reach ground (g=10):', '2 s', 'sqrt2 s', '4 s', 'sqrt5 s', 'A', 'h = (1/2)gt^2 -> t = sqrt(2h/g) = sqrt(40/10) = 2 s'),
('f1110002-0000-0000-0000-000000000008', 'a1111111-1111-1111-1111-111111111111', 'f1110002-0000-0000-0000-000000000002', 'MEDIUM', 'Relative velocity of rain falling vertically at 10 m/s as seen by man walking at 10 m/s:', '10 m/s', '10sqrt2 m/s', '20 m/s', '0', 'B', '|Vrel| = sqrt(10^2+10^2) = 10sqrt2 m/s at 45 degrees'),
('f1110002-0000-0000-0000-000000000009', 'a1111111-1111-1111-1111-111111111111', 'f1110002-0000-0000-0000-000000000002', 'MEDIUM', 'A -> * B -> = 0 implies:', 'A and B are perpendicular', 'A and B are parallel', '|A|=0 or |B|=0 or parallel', 'Both B and C', 'D', 'Cross product is zero when vectors are parallel/antiparallel or one is zero'),
('f1110002-0000-0000-0000-000000000010', 'a1111111-1111-1111-1111-111111111111', 'f1110002-0000-0000-0000-000000000002', 'MEDIUM', 'Range of projectile at theta=30 degrees equals range at theta=?', '60 degrees', '45 degrees', '75 degrees', '90 degrees', 'A', 'R(theta) = R(90 degrees-theta). complementary angles give same range. R(30 degrees)=R(60 degrees)'),
('f1110002-0000-0000-0000-000000000011', 'a1111111-1111-1111-1111-111111111111', 'f1110002-0000-0000-0000-000000000002', 'MEDIUM', 'Horizontal range of projectile with u=40 m/s at 45 degrees (g=10 m/s^2):', '80 m', '160 m', '40 m', '120 m', 'B', 'R = u^2sin2theta/g = 1600*1/10 = 160 m'),
('f1110002-0000-0000-0000-000000000012', 'a1111111-1111-1111-1111-111111111111', 'f1110002-0000-0000-0000-000000000002', 'MEDIUM', 'A particle moves in a circle of radius r with speed v. Its centripetal acceleration is:', 'v/r', 'v^2r', 'v^2/r', 'vr^2', 'C', 'ac = v^2/r (centripetal acceleration)'),
('f1110002-0000-0000-0000-000000000013', 'a1111111-1111-1111-1111-111111111111', 'f1110002-0000-0000-0000-000000000002', 'MEDIUM', 'The angle between A= +j and B= -j is:', '0 degrees', '45 degrees', '90 degrees', '180 degrees', 'C', 'A B = 1-1 = 0 -> perpendicular -> 90 degrees'),
('f1110002-0000-0000-0000-000000000014', 'a1111111-1111-1111-1111-111111111111', 'f1110002-0000-0000-0000-000000000002', 'MEDIUM', 'A river flows at 4 m/s. Swimmer swims at 3 m/s perpendicular. Resultant speed:', '5 m/s', '7 m/s', '1 m/s', '12 m/s', 'A', 'Vres = sqrt(4^2+3^2) = sqrt25 = 5 m/s'),
('f1110002-0000-0000-0000-000000000015', 'a1111111-1111-1111-1111-111111111111', 'f1110002-0000-0000-0000-000000000002', 'HARD', 'For same launch speed, angle giving equal range to 30 degrees angle is:', '60 degrees', '45 degrees', '75 degrees', '15 degrees', 'A', 'Complementary angles: 90 degrees-30 degrees=60 degrees'),
('f1110002-0000-0000-0000-000000000016', 'a1111111-1111-1111-1111-111111111111', 'f1110002-0000-0000-0000-000000000002', 'HARD', 'A body is thrown with velocity 20 m/s at 60 degrees. Speed at highest point (g=10):', '10 m/s', '20 m/s', '0', '10sqrt3 m/s', 'A', 'At top, v = u costheta = 20 cos60 degrees = 20*0.5 = 10 m/s'),
('f1110002-0000-0000-0000-000000000017', 'a1111111-1111-1111-1111-111111111111', 'f1110002-0000-0000-0000-000000000002', 'HARD', 'Maximum height to range ratio for projectile at angle theta is:', 'tantheta', 'tantheta/4', 'sintheta/2', '2tantheta', 'B', 'H/R = (u^2sin^2theta/2g)/(u^2sin2theta/g) = sintheta/(4costheta) = tantheta/4'),
('f1110002-0000-0000-0000-000000000018', 'a1111111-1111-1111-1111-111111111111', 'f1110002-0000-0000-0000-000000000002', 'HARD', 'A shell fired at 45 degrees explodes at highest point into two equal pieces horizontally. One piece falls vertically. How far does other piece land from firing point? (R = normal range):', '3R/2', '2R', 'R', 'R/2', 'A', 'At top, COM has horizontal velocity u/sqrt2. One piece stops -> other has velocity 2*u/sqrt2. Remaining height H=R/4, extra range = 2u/sqrt2 * t from top -> total = R + R/2 = 3R/2'),
('f1110002-0000-0000-0000-000000000019', 'a1111111-1111-1111-1111-111111111111', 'f1110002-0000-0000-0000-000000000002', 'HARD', 'Scalar product A B = AB costheta. If A B = |A*B|, angle between vectors is:', '0 degrees', '30 degrees', '45 degrees', '90 degrees', 'C', 'AB costheta = AB sintheta -> tantheta=1 -> theta=45 degrees'),
('f1110002-0000-0000-0000-000000000020', 'a1111111-1111-1111-1111-111111111111', 'f1110002-0000-0000-0000-000000000002', 'HARD', 'A particle moves along y = x^2. At x=2, velocity makes angle with x-axis:', 'tan-^1(4)', 'tan-^1(2)', '45 degrees', '30 degrees', 'A', 'dy/dx = 2x = 4 at x=2. tantheta = vy/vx = 4 -> theta = tan-^1(4)'),
('f1110002-0000-0000-0000-000000000021', 'a1111111-1111-1111-1111-111111111111', 'f1110002-0000-0000-0000-000000000002', 'MEDIUM', 'A bullet is fired horizontally and another dropped from same height simultaneously. Which hits ground first?', 'Bullet', 'Dropped', 'Both simultaneously', 'Depends on mass', 'C', 'Both have same vertical acceleration g. hit ground simultaneously')
INSERT INTO questions (id, subject_id, topic_id, difficulty, question_text, option_a, option_b, option_c, option_d, correct_answer, solution) VALUES
('f1110002-0000-0000-0000-000000000022', 'a1111111-1111-1111-1111-111111111111', 'f1110002-0000-0000-0000-000000000002', 'MEDIUM', 'Position vector of particle at t=2s is 3 +4j and at t=4s is 7 +8j. Average velocity vector:', '2 +2j', '4 +4j', '2 +4j', '+j', 'A', 'Deltar=(7-3) +(8-4)j=4 +4j. Deltat=2. v_avg=2 +2j m/s'),
('f1110002-0000-0000-0000-000000000023', 'a1111111-1111-1111-1111-111111111111', 'f1110002-0000-0000-0000-000000000002', 'MEDIUM', 'Area of parallelogram formed by vectors A=3 and B=4j is:', '12', '7', '0', '24', 'A', 'Area = |A*B| = |3 *4j| = 12|k| = 12 sq units'),
('f1110002-0000-0000-0000-000000000024', 'a1111111-1111-1111-1111-111111111111', 'f1110002-0000-0000-0000-000000000002', 'MEDIUM', 'In uniform circular motion, which quantity is constant?', 'Velocity', 'Speed', 'Acceleration magnitude', 'All except velocity', 'D', 'In UCM: speed constant, but velocity and acceleration direction change. magnitude of acceleration constant'),
('f1110002-0000-0000-0000-000000000025', 'a1111111-1111-1111-1111-111111111111', 'f1110002-0000-0000-0000-000000000002', 'HARD', 'A projectile has same range for projection angles theta and 90 degrees-theta. If R_1=R_2, ratio of their times of flight T_1/T_2 is:', 'tantheta', 'cottheta', 'sin2theta', '1', 'A', 'T = 2u sintheta/g. T_1/T_2 = sintheta/sin(90 degrees-theta) = sintheta/costheta = tantheta'),
('f1110002-0000-0000-0000-000000000026', 'a1111111-1111-1111-1111-111111111111', 'f1110002-0000-0000-0000-000000000002', 'EASY', 'Unit vector in direction of 3 +4j is:', '3 +4j', '(3 +4j)/5', '(3 +4j)/7', '(3 +4j)/25', 'B', '|v|=sqrt(9+16)=5. unit vector=(3 +4j)/5'),
('f1110002-0000-0000-0000-000000000027', 'a1111111-1111-1111-1111-111111111111', 'f1110002-0000-0000-0000-000000000002', 'MEDIUM', 'A stone thrown at 45 degrees covers horizontal range 40 m. The initial velocity is (g=10):', '20 m/s', '10sqrt2 m/s', '20sqrt2 m/s', '10 m/s', 'A', 'R=u^2/g (for 45 degrees). 40=u^2/10. u^2=400. u=20 m/s'),
('f1110002-0000-0000-0000-000000000028', 'a1111111-1111-1111-1111-111111111111', 'f1110002-0000-0000-0000-000000000002', 'MEDIUM', 'The trajectory of projectile is parabolic because:', 'Horizontal acceleration is constant', 'Vertical velocity is constant', 'Horizontal velocity is constant and vertical has constant acceleration', 'Both velocities are constant', 'C', 'x = u costheta t (uniform), y = u sintheta t - gt^2 (quadratic) -> parabola'),
('f1110002-0000-0000-0000-000000000029', 'a1111111-1111-1111-1111-111111111111', 'f1110002-0000-0000-0000-000000000002', 'HARD', 'Two projectiles have same range. One is fired at 30 degrees and other at 60 degrees. Ratio of their maximum heights H_1:H_2:', '1:3', '3:1', '1:2', '1:sqrt3', 'A', 'H sin^2theta. H_1/H_2 = sin^230 degrees/sin^260 degrees = (1/4)/(3/4) = 1:3'),
('f1110002-0000-0000-0000-000000000030', 'a1111111-1111-1111-1111-111111111111', 'f1110002-0000-0000-0000-000000000002', 'HARD', 'A particle moves with velocity v = 2t + 3t^2j. Acceleration at t=2s is:', '2 +6j', '2 +12j', '4 +12j', '2 +3j', 'B', 'a=dv/dt=2 +6tj. at t=2: a=2 +12j m/s^2')
INSERT INTO questions (id, subject_id, topic_id, difficulty, question_text, option_a, option_b, option_c, option_d, correct_answer, solution) VALUES
('f1110003-0000-0000-0000-000000000001', 'a1111111-1111-1111-1111-111111111111', 'f1110003-0000-0000-0000-000000000003', 'EASY', 'A body of mass 5 kg is acted on by net force 20 N. Acceleration is:', '4 m/s^2', '100 m/s^2', '0.25 m/s^2', '15 m/s^2', 'A', 'a=F/m=20/5=4 m/s^2'),
('f1110003-0000-0000-0000-000000000002', 'a1111111-1111-1111-1111-111111111111', 'f1110003-0000-0000-0000-000000000003', 'EASY', 'Newton''s first law defines:', 'Force', 'Inertia', 'Acceleration', 'Momentum', 'B', 'First law defines inertia: body continues in state of rest/motion unless force acts'),
('f1110003-0000-0000-0000-000000000003', 'a1111111-1111-1111-1111-111111111111', 'f1110003-0000-0000-0000-000000000003', 'EASY', 'Impulse of a force equals:', 'Force * distance', 'Change in KE', 'Change in momentum', 'Force * acceleration', 'C', 'Impulse = F*Deltat = Deltap (change in momentum)')
INSERT INTO questions (id, subject_id, topic_id, difficulty, question_text, option_a, option_b, option_c, option_d, correct_answer, solution) VALUES
('f1110004-0000-0000-0000-000000000001', 'a1111111-1111-1111-1111-111111111111', 'f1110004-0000-0000-0000-000000000004', 'EASY', 'Escape velocity from Earth (g=9.8 m/s^2, R=6400 km) is approximately:', '7.9 km/s', '11.2 km/s', '5 km/s', '16 km/s', 'B', 've=sqrt(2gR)=sqrt(2*9.8*6.4*10^6)~=11.2 km/s'),
('f1110004-0000-0000-0000-000000000002', 'a1111111-1111-1111-1111-111111111111', 'f1110004-0000-0000-0000-000000000004', 'EASY', 'Orbital speed of satellite at height h above Earth (R=radius, g=surface gravity):', 'sqrt(gR)', 'sqrt(gR^2/(R+h))', 'sqrt(g(R+h))', 'gR^2/(R+h)', 'B', 'v_0=sqrt(GM/(R+h))=sqrt(gR^2/(R+h))'),
('f1110004-0000-0000-0000-000000000003', 'a1111111-1111-1111-1111-111111111111', 'f1110004-0000-0000-0000-000000000004', 'EASY', 'Geostationary satellite orbits at height approximately:', '200 km', '6400 km', '36000 km', '384000 km', 'C', 'Geostationary orbit ~= 36000 km above Earth''s surface'),
('f1110004-0000-0000-0000-000000000004', 'a1111111-1111-1111-1111-111111111111', 'f1110004-0000-0000-0000-000000000004', 'EASY', 'Kepler''s third law states T^2 :', 'r', 'r^2', 'r^3', 'r^4', 'C', 'Kepler''s 3rd law: T^2 r^3 (r = semi-major axis)'),
('f1110004-0000-0000-0000-000000000006', 'a1111111-1111-1111-1111-111111111111', 'f1110004-0000-0000-0000-000000000004', 'MEDIUM', 'Gravitational PE of satellite of mass m at height h above Earth (M=Earth mass):', '-GMm/h', '-GMm/(R+h)', 'GMm/(R+h)', 'GMmg/h', 'B', 'PE = -GMm/r = -GMm/(R+h)'),
('f1110004-0000-0000-0000-000000000007', 'a1111111-1111-1111-1111-111111111111', 'f1110004-0000-0000-0000-000000000004', 'MEDIUM', 'If Earth''s radius reduces to half keeping mass same, g at surface becomes:', 'g/4', 'g/2', '2g', '4g', 'D', 'g=GM/R^2. if R->R/2, g->GM/(R/2)^2=4g'),
('f1110004-0000-0000-0000-000000000008', 'a1111111-1111-1111-1111-111111111111', 'f1110004-0000-0000-0000-000000000004', 'MEDIUM', 'The period of satellite orbiting at Earth''s surface (R=6400km, g=9.8 m/s^2) is approximately:', '84 min', '24 hours', '90 min', '60 min', 'A', 'T=2pisqrt(R/g)=2pisqrt(6.4*10^6/9.8)~=5070s~=84.5 min'),
('f1110004-0000-0000-0000-000000000009', 'a1111111-1111-1111-1111-111111111111', 'f1110004-0000-0000-0000-000000000004', 'MEDIUM', 'Energy required to move satellite from orbit r_1 to r_2 (r_2>r_1) is:', 'Positive', 'Negative', 'Zero', 'Depends on mass', 'A', 'Moving to higher orbit requires positive work input -> positive energy'),
('f1110004-0000-0000-0000-000000000010', 'a1111111-1111-1111-1111-111111111111', 'f1110004-0000-0000-0000-000000000004', 'MEDIUM', 'If mass of satellite doubles, orbital velocity:', 'Doubles', 'Halves', 'Remains same', 'Increases by sqrt2', 'C', 'v_0=sqrt(GM/r). independent of satellite mass'),
('f1110004-0000-0000-0000-000000000011', 'a1111111-1111-1111-1111-111111111111', 'f1110004-0000-0000-0000-000000000004', 'EASY', 'Gravitational force between Earth and Moon is an example of:', 'Contact force', 'Non-contact force', 'Magnetic force', 'Normal force', 'B', 'Gravity acts at distance without contact -> non-contact force'),
('f1110004-0000-0000-0000-000000000012', 'a1111111-1111-1111-1111-111111111111', 'f1110004-0000-0000-0000-000000000004', 'MEDIUM', 'Weight of body at centre of Earth is:', 'mg', 'mg/2', '2mg', 'Zero', 'D', 'At centre, g=0. weight = mg = 0'),
('f1110004-0000-0000-0000-000000000013', 'a1111111-1111-1111-1111-111111111111', 'f1110004-0000-0000-0000-000000000004', 'HARD', 'Time period of satellite at height equal to Earth radius R (above surface):', '2pisqrt(R/g)', '2pisqrt(2R/g)', '2sqrt2 pisqrt(R/g)', '4pisqrt(R/g)', 'C', 'At r=2R from centre: T=2pisqrt(r^3/GM)=2pisqrt(8R^3/gR^2)=2pi*2sqrt2*sqrt(R/g)=2sqrt2pisqrt(R/g)'),
('f1110004-0000-0000-0000-000000000014', 'a1111111-1111-1111-1111-111111111111', 'f1110004-0000-0000-0000-000000000004', 'HARD', 'Binding energy of satellite of mass m in orbit of radius r is:', 'GMm/2r', 'GMm/r', '-GMm/2r', '2GMm/r', 'A', 'BE = -TE = -(-GMm/2r) = GMm/2r'),
('f1110004-0000-0000-0000-000000000015', 'a1111111-1111-1111-1111-111111111111', 'f1110004-0000-0000-0000-000000000004', 'MEDIUM', 'Escape velocity is independent of:', 'Mass of planet', 'Radius of planet', 'Mass of projected body', 'G', 'C', 've=sqrt(2gR)=sqrt(2GM/R). no dependence on mass of body'),
('f1110004-0000-0000-0000-000000000016', 'a1111111-1111-1111-1111-111111111111', 'f1110004-0000-0000-0000-000000000004', 'HARD', 'Ratio of escape velocity to orbital velocity for near-Earth satellite:', '1', 'sqrt2', '2', '1/sqrt2', 'B', 've=sqrt(2gR), v_0=sqrt(gR). ve/v_0=sqrt2'),
('f1110004-0000-0000-0000-000000000017', 'a1111111-1111-1111-1111-111111111111', 'f1110004-0000-0000-0000-000000000004', 'MEDIUM', 'A satellite in orbit is given extra velocity. It will:', 'Fall to Earth', 'Go to higher orbit', 'Remain in same orbit', 'Crash into Moon', 'B', 'Increasing velocity -> more KE -> satellite moves to higher orbit'),
('f1110004-0000-0000-0000-000000000018', 'a1111111-1111-1111-1111-111111111111', 'f1110004-0000-0000-0000-000000000004', 'MEDIUM', 'Gravitational potential at surface of Earth (M, R) is:', '-GM/R', 'GM/R', '-GMm/R', 'Zero', 'A', 'V = -GM/R (negative, reference at infinity)'),
('f1110004-0000-0000-0000-000000000019', 'a1111111-1111-1111-1111-111111111111', 'f1110004-0000-0000-0000-000000000004', 'HARD', 'Two satellites orbit at radii r and 4r. Ratio of their speeds v_1:v_2 is:', '1:2', '2:1', '1:4', '4:1', 'B', 'v 1/sqrtr. v_1/v_2=sqrt(4r/r)=sqrt4=2 -> v_1:v_2=2:1'),
('f1110004-0000-0000-0000-000000000020', 'a1111111-1111-1111-1111-111111111111', 'f1110004-0000-0000-0000-000000000004', 'MEDIUM', 'Kepler''s second law (equal areas) is consequence of conservation of:', 'Energy', 'Linear momentum', 'Angular momentum', 'Mass', 'C', 'No torque about Sun -> angular momentum conserved -> equal areas'),
('f1110004-0000-0000-0000-000000000021', 'a1111111-1111-1111-1111-111111111111', 'f1110004-0000-0000-0000-000000000004', 'EASY', 'Gravitational field intensity at distance r from mass M is:', 'GM/r', 'GM/r^2', '-GM/r^2', 'GMm/r^2', 'B', 'g = GM/r^2 (field = force per unit mass)')
INSERT INTO questions (id, subject_id, topic_id, difficulty, question_text, option_a, option_b, option_c, option_d, correct_answer, solution) VALUES
('f1110004-0000-0000-0000-000000000022', 'a1111111-1111-1111-1111-111111111111', 'f1110004-0000-0000-0000-000000000004', 'MEDIUM', 'g at poles is greater than at equator because:', 'Earth is oblate (flatter at poles, polar radius < equatorial)', 'Earth rotates faster at poles', 'Density is more at poles', 'Temperature is lower', 'A', 'Polar radius < equatorial radius. g=GM/R^2 -> larger g at poles'),
('f1110004-0000-0000-0000-000000000023', 'a1111111-1111-1111-1111-111111111111', 'f1110004-0000-0000-0000-000000000004', 'HARD', 'A planet has mass 2M and radius 2R compared to Earth. Escape velocity from planet vs Earth:', 'Same', 'Double', 'Half', '4 times', 'A', 've=sqrt(2GM/R). planet: sqrt(2G*2M/2R)=sqrt(2GM/R)=same as Earth'),
('f1110004-0000-0000-0000-000000000024', 'a1111111-1111-1111-1111-111111111111', 'f1110004-0000-0000-0000-000000000004', 'HARD', 'Total energy of satellite in orbit r is:', '-GMm/r', 'GMm/r', '-GMm/2r', 'GMm/2r', 'C', 'TE = KE + PE = GMm/2r - GMm/r = -GMm/2r'),
('f1110004-0000-0000-0000-000000000025', 'a1111111-1111-1111-1111-111111111111', 'f1110004-0000-0000-0000-000000000004', 'EASY', 'Newton''s law of gravitation: F = Gm_1m_2/r^2. The value of G in SI is:', '6.67*10-^1^1 Nm^2/kg^2', '9.8 Nm^2/kg^2', '6.67*10-^8 Nm^2/kg^2', '6.67*10-^9 Nm^2/kg^2', 'A', 'G = 6.67*10-^1^1 N m^2/kg^2'),
('f1110004-0000-0000-0000-000000000026', 'a1111111-1111-1111-1111-111111111111', 'f1110004-0000-0000-0000-000000000004', 'HARD', 'If orbital radius of satellite doubles, time period changes by factor:', '2', '2sqrt2', '4', 'sqrt2', 'B', 'T r^(3/2). T_2/T_1=(2r/r)^(3/2)=2^(3/2)=2sqrt2'),
('f1110004-0000-0000-0000-000000000027', 'a1111111-1111-1111-1111-111111111111', 'f1110004-0000-0000-0000-000000000004', 'HARD', 'Weightlessness in satellite is because:', 'Gravity is zero', 'Gravity is balanced by centrifugal force', 'Both satellite and person fall freely together', 'Air resistance acts', 'C', 'Both satellite and occupant are in free fall (same acceleration g). apparent weight = 0'),
('f1110004-0000-0000-0000-000000000028', 'a1111111-1111-1111-1111-111111111111', 'f1110004-0000-0000-0000-000000000004', 'MEDIUM', 'Gravitational PE at height h above surface (h<<R) is approximately:', 'mgh', 'mg(R+h)', '-mgh', 'mgRh', 'A', 'For small h: DeltaPE = mgh (approximate, taking surface as zero)'),
('f1110004-0000-0000-0000-000000000029', 'a1111111-1111-1111-1111-111111111111', 'f1110004-0000-0000-0000-000000000004', 'HARD', 'The gravitational force between two bodies is 100 N. If both masses are doubled:', '100 N', '200 N', '400 N', '50 N', 'C', 'F m_1m_2. doubling both -> F*4 = 400 N'),
('f1110004-0000-0000-0000-000000000030', 'a1111111-1111-1111-1111-111111111111', 'f1110004-0000-0000-0000-000000000004', 'HARD', 'On Moon (g_moon = g/6), escape velocity compared to Earth is:', 've/6', 've/sqrt6', 've/2', 've*sqrt6', 'B', 've=sqrt(2gR). Moon: sqrt(2*g/6*R_moon). with R_moon~=R/4: ve_moon=vesqrt(1/6*1/4*... ) actually ratio depends on both g and R')
INSERT INTO questions (id, subject_id, topic_id, difficulty, question_text, option_a, option_b, option_c, option_d, correct_answer, solution) VALUES
('f1110005-0000-0000-0000-000000000001', 'a1111111-1111-1111-1111-111111111111', 'f1110005-0000-0000-0000-000000000005', 'EASY', 'SI unit of heat is:', 'Calorie', 'Joule', 'BTU', 'Erg', 'B', 'SI unit of heat is Joule (J)'),
('f1110005-0000-0000-0000-000000000002', 'a1111111-1111-1111-1111-111111111111', 'f1110005-0000-0000-0000-000000000005', 'EASY', '1 calorie = __ joules:', '0.24', '4.2', '42', '0.042', 'B', '1 cal = 4.2 J (mechanical equivalent of heat)')
INSERT INTO questions (id, subject_id, topic_id, difficulty, question_text, option_a, option_b, option_c, option_d, correct_answer, solution) VALUES
('f1110006-0000-0000-0000-000000000001', 'a1111111-1111-1111-1111-111111111111', 'f1110006-0000-0000-0000-000000000006', 'EASY', 'Speed of sound in air at 0 degreesC is approximately:', '232 m/s', '332 m/s', '432 m/s', '532 m/s', 'B', 'v_sound ~= 332 m/s at 0 degreesC in air'),
('f1110006-0000-0000-0000-000000000002', 'a1111111-1111-1111-1111-111111111111', 'f1110006-0000-0000-0000-000000000006', 'EASY', 'Sound waves are __ waves:', 'Transverse', 'Longitudinal', 'Electromagnetic', 'Surface', 'B', 'Sound = longitudinal mechanical waves (compression/rarefaction)'),
('f1110006-0000-0000-0000-000000000003', 'a1111111-1111-1111-1111-111111111111', 'f1110006-0000-0000-0000-000000000006', 'EASY', 'Frequency of a wave is 500 Hz and speed is 340 m/s. Wavelength is:', '0.68 m', '170 m', '68 m', '1.47 m', 'A', 'lambda = v/f = 340/500 = 0.68 m'),
('f1110006-0000-0000-0000-000000000004', 'a1111111-1111-1111-1111-111111111111', 'f1110006-0000-0000-0000-000000000006', 'EASY', 'Doppler effect is change in observed __ due to relative motion:', 'Amplitude', 'Frequency', 'Speed', 'Phase', 'B', 'Doppler effect: change in observed frequency due to relative motion'),
('f1110006-0000-0000-0000-000000000005', 'a1111111-1111-1111-1111-111111111111', 'f1110006-0000-0000-0000-000000000006', 'EASY', 'Beat frequency = |f_1 - f_2|. Two tuning forks of 440 Hz and 444 Hz produce __ beats/s:', '4', '884', '440', '444', 'A', 'Beat freq = |440-444| = 4 beats/s'),
('f1110006-0000-0000-0000-000000000006', 'a1111111-1111-1111-1111-111111111111', 'f1110006-0000-0000-0000-000000000006', 'MEDIUM', 'In open organ pipe, fundamental frequency for length L is:', 'v/4L', 'v/2L', 'v/L', '2v/L', 'B', 'Open pipe: f_1 = v/2L (antinode at both ends)'),
('f1110006-0000-0000-0000-000000000007', 'a1111111-1111-1111-1111-111111111111', 'f1110006-0000-0000-0000-000000000006', 'MEDIUM', 'A closed organ pipe produces __ harmonics only:', 'Even', 'Odd', 'All', 'None', 'B', 'Closed pipe: only odd harmonics (1st, 3rd, 5th...)'),
('f1110006-0000-0000-0000-000000000009', 'a1111111-1111-1111-1111-111111111111', 'f1110006-0000-0000-0000-000000000006', 'MEDIUM', 'Speed of sound in air at T degreesC is v_0 at 0 degreesC. At T degreesC:', 'v_0(1+T/273)', 'v_0sqrt(1+T/273)', 'v_0(1+T/546)', 'v_0*T/273', 'B', 'v sqrtT. v_T=v_0sqrt(T_K/273)=v_0sqrt(1+T/273)'),
('f1110006-0000-0000-0000-000000000010', 'a1111111-1111-1111-1111-111111111111', 'f1110006-0000-0000-0000-000000000006', 'MEDIUM', 'When a source moves away from observer, apparent frequency:', 'Increases', 'Decreases', 'Stays same', 'Becomes zero', 'B', 'Source moving away -> wavelength increases -> frequency decreases (redshift)'),
('f1110006-0000-0000-0000-000000000011', 'a1111111-1111-1111-1111-111111111111', 'f1110006-0000-0000-0000-000000000006', 'MEDIUM', 'Resonance is a special case of:', 'Beats', 'Forced vibration', 'Free vibration', 'Damped vibration', 'B', 'Resonance: forced vibration at natural frequency -> maximum amplitude'),
('f1110006-0000-0000-0000-000000000012', 'a1111111-1111-1111-1111-111111111111', 'f1110006-0000-0000-0000-000000000006', 'MEDIUM', 'An organ pipe open at both ends. If length = 0.5m and v=340m/s, fundamental freq:', '340 Hz', '680 Hz', '170 Hz', '85 Hz', 'A', 'f = v/2L = 340/(2*0.5) = 340 Hz'),
('f1110006-0000-0000-0000-000000000013', 'a1111111-1111-1111-1111-111111111111', 'f1110006-0000-0000-0000-000000000006', 'MEDIUM', 'Intensity of sound decreases with distance r as:', '1/r', '1/r^2', '1/r^3', 'r^2', 'B', 'Intensity 1/r^2 (inverse square law for point source)'),
('f1110006-0000-0000-0000-000000000014', 'a1111111-1111-1111-1111-111111111111', 'f1110006-0000-0000-0000-000000000006', 'MEDIUM', 'The decibel scale for sound intensity: if I_1/I_0 = 10^1^0, sound level is:', '10 dB', '100 dB', '1000 dB', '50 dB', 'B', 'beta = 10 log(I/I_0) = 10*10 = 100 dB'),
('f1110006-0000-0000-0000-000000000015', 'a1111111-1111-1111-1111-111111111111', 'f1110006-0000-0000-0000-000000000006', 'HARD', 'A tuning fork of 512 Hz produces 4 beats with unknown fork. On loading unknown fork, beats reduce to 2. Unknown fork frequency is:', '508 Hz', '516 Hz', '514 Hz', '510 Hz', 'A', 'Loading reduces frequency. beats decrease from 4 to 2 -> unknown is below 512. was 508 Hz'),
('f1110006-0000-0000-0000-000000000016', 'a1111111-1111-1111-1111-111111111111', 'f1110006-0000-0000-0000-000000000006', 'HARD', 'Standing wave has nodes and antinodes. Distance between adjacent node and antinode is:', 'lambda', 'lambda/2', 'lambda/4', 'lambda/8', 'C', 'Adjacent node-antinode spacing = lambda/4'),
('f1110006-0000-0000-0000-000000000017', 'a1111111-1111-1111-1111-111111111111', 'f1110006-0000-0000-0000-000000000006', 'HARD', 'Equation of a wave: y = A sin(kx - omegat). Phase velocity is:', 'omega/k', 'k/omega', 'Aomega', 'komega', 'A', 'Phase velocity v_phase = omega/k'),
('f1110006-0000-0000-0000-000000000018', 'a1111111-1111-1111-1111-111111111111', 'f1110006-0000-0000-0000-000000000006', 'HARD', 'Laplace correction modifies Newton''s formula because sound propagation is:', 'Isothermal', 'Isobaric', 'Adiabatic', 'Isochoric', 'C', 'Rapid compression/expansion is adiabatic not isothermal. v = sqrt(gammaP/rho)'),
('f1110006-0000-0000-0000-000000000019', 'a1111111-1111-1111-1111-111111111111', 'f1110006-0000-0000-0000-000000000006', 'HARD', 'For a closed pipe of length 0.5m (v=340m/s), the 3rd harmonic frequency is:', '510 Hz', '340 Hz', '1020 Hz', '680 Hz', 'C', 'Closed pipe 3rd harmonic (3rd odd = 3f_1): f_1=v/4L=340/2=170Hz. 3rd harm=3*170*... wait: 1st harm=170Hz. 3rd harm=3*170=510Hz... no: n=1,3,5. 3rd harmonic is n=3: 3*170=510Hz'),
('f1110006-0000-0000-0000-000000000020', 'a1111111-1111-1111-1111-111111111111', 'f1110006-0000-0000-0000-000000000006', 'HARD', 'Two identical strings under same tension. One has double length. Ratio of fundamental frequencies f_1:f_2:', '2:1', '1:2', '1:4', '4:1', 'B', 'f = v/2L. f 1/L. f_1/f_2 = L_2/L_1 = 1/2 -> f_1:f_2 = 1:2'),
('f1110006-0000-0000-0000-000000000021', 'a1111111-1111-1111-1111-111111111111', 'f1110006-0000-0000-0000-000000000006', 'MEDIUM', 'Echo requires minimum distance between source and reflector (v=340m/s) of:', '17 m', '34 m', '10 m', '50 m', 'A', 'Persistence of hearing = 1/10 s. min distance = v*t/2 = 340*0.1/2 = 17 m')
INSERT INTO questions (id, subject_id, topic_id, difficulty, question_text, option_a, option_b, option_c, option_d, correct_answer, solution) VALUES
('f1110006-0000-0000-0000-000000000022', 'a1111111-1111-1111-1111-111111111111', 'f1110006-0000-0000-0000-000000000006', 'EASY', 'Ultrasonic waves have frequency:', '< 20 Hz', '20 Hz to 20 kHz', '> 20 kHz', 'None', 'C', 'Ultrasonic: frequency > 20 kHz (above human hearing range)'),
('f1110006-0000-0000-0000-000000000023', 'a1111111-1111-1111-1111-111111111111', 'f1110006-0000-0000-0000-000000000006', 'MEDIUM', 'In SONAR, time for echo to return is 4 s. Distance of object if v_sound in water = 1500 m/s:', '3000 m', '6000 m', '1500 m', '750 m', 'A', 'd = v*t/2 = 1500*4/2 = 3000 m'),
('f1110006-0000-0000-0000-000000000024', 'a1111111-1111-1111-1111-111111111111', 'f1110006-0000-0000-0000-000000000006', 'MEDIUM', 'Frequency of vibration of string: f = (1/2L)sqrt(T/mu). If tension quadruples, frequency:', 'Halves', 'Doubles', 'Quadruples', 'Stays same', 'B', 'f sqrtT. T*4 -> f*sqrt4=2. frequency doubles'),
('f1110006-0000-0000-0000-000000000025', 'a1111111-1111-1111-1111-111111111111', 'f1110006-0000-0000-0000-000000000006', 'EASY', 'Formation of beats requires two waves with:', 'Same amplitude and same frequency', 'Nearly equal frequencies', 'Large frequency difference', 'Same phase', 'B', 'Beats formed by superposition of waves with slightly different frequencies'),
('f1110006-0000-0000-0000-000000000026', 'a1111111-1111-1111-1111-111111111111', 'f1110006-0000-0000-0000-000000000006', 'HARD', 'A train moving at 72 km/h sounds horn at 600 Hz. Observer in front hears (v=340 m/s):', '600 Hz', '636 Hz', '566 Hz', '680 Hz', 'B', 'v_s=20m/s. f''=f*v/(v-v_s)=600*340/320=600*1.0625~=637.5~=636 Hz'),
('f1110006-0000-0000-0000-000000000027', 'a1111111-1111-1111-1111-111111111111', 'f1110006-0000-0000-0000-000000000006', 'MEDIUM', 'Sound travels fastest in:', 'Air', 'Water', 'Steel', 'Vacuum', 'C', 'Speed of sound: solids > liquids > gases. steel ~= 5100 m/s'),
('f1110006-0000-0000-0000-000000000028', 'a1111111-1111-1111-1111-111111111111', 'f1110006-0000-0000-0000-000000000006', 'EASY', 'Mach number is ratio of speed of object to:', 'Speed of light', 'Speed of sound', 'Speed of wind', 'Speed of projectile', 'B', 'Mach number = v_object/v_sound'),
('f1110006-0000-0000-0000-000000000029', 'a1111111-1111-1111-1111-111111111111', 'f1110006-0000-0000-0000-000000000006', 'HARD', 'In standing wave, energy is:', 'Transported from node to antinode', 'Transferred along the wave', 'Localized between nodes', 'Zero everywhere', 'C', 'Standing waves do not transfer energy. energy is localized between nodes'),
('f1110006-0000-0000-0000-000000000030', 'a1111111-1111-1111-1111-111111111111', 'f1110006-0000-0000-0000-000000000006', 'HARD', 'Fundamental frequency of a wire of mass M, length L under tension T is:', '(1/2L)sqrt(T/M/L)', '(1/2L)sqrt(TL/M)', '(1/L)sqrt(T/M)', 'sqrt(TL/M)', 'A', 'mu=M/L. f=(1/2L)sqrt(T/mu)=(1/2L)sqrt(TL/M)... so answer B? f=(1/2L)sqrt(TL/M): let''s verify: mu=M/L. f=(1/2L)sqrt(T/(M/L))=(1/2L)sqrt(TL/M)')
INSERT INTO questions (id, subject_id, topic_id, difficulty, question_text, option_a, option_b, option_c, option_d, correct_answer, solution) VALUES
('f1110007-0000-0000-0000-000000000001', 'a1111111-1111-1111-1111-111111111111', 'f1110007-0000-0000-0000-000000000007', 'EASY', 'Laws of reflection state angle of incidence __ angle of reflection:', 'Greater than', 'Less than', 'Equal to', 'Unrelated to', 'C', 'Law of reflection: angle of incidence = angle of reflection'),
('f1110007-0000-0000-0000-000000000002', 'a1111111-1111-1111-1111-111111111111', 'f1110007-0000-0000-0000-000000000007', 'EASY', 'Refractive index n = c/v. If n=1.5, speed of light in medium:', '3*10^8 m/s', '2*10^8 m/s', '4.5*10^8 m/s', '1*10^8 m/s', 'B', 'v = c/n = 3*10^8/1.5 = 2*10^8 m/s')
INSERT INTO questions (id, subject_id, topic_id, difficulty, question_text, option_a, option_b, option_c, option_d, correct_answer, solution) VALUES
('f1110008-0000-0000-0000-000000000001', 'a1111111-1111-1111-1111-111111111111', 'f1110008-0000-0000-0000-000000000008', 'EASY', 'Force between two charges of 1muC each separated by 1m (k=9*10^9):', '9*10-^3 N', '9*10-^6 N', '9*10^3 N', '9*10-^1^2 N', 'A', 'F=kq_1q_2/r^2=9*10^9*10-^6*10-^6/1=9*10-^3 N'),
('f1110008-0000-0000-0000-000000000002', 'a1111111-1111-1111-1111-111111111111', 'f1110008-0000-0000-0000-000000000008', 'MEDIUM', 'Electric field due to +10muC at 3m from it:', '10000 V/m', '10 kV/m', '10 V/m', '100 kV/m', 'A', 'E=kQ/r^2=9*10^9*10-^5/9=10^4=10000 V/m'),
('f1110008-0000-0000-0000-000000000003', 'a1111111-1111-1111-1111-111111111111', 'f1110008-0000-0000-0000-000000000008', 'EASY', 'Work done in moving charge q through potential difference V is:', 'qV', 'q/V', 'V/q', 'q^2V', 'A', 'W = qV'),
('f1110008-0000-0000-0000-000000000004', 'a1111111-1111-1111-1111-111111111111', 'f1110008-0000-0000-0000-000000000008', 'EASY', 'Inside a conducting sphere, electric field is:', 'Maximum at centre', 'Increases toward centre', 'Zero everywhere', 'Equal to surface value', 'C', 'E=0 inside conductor in electrostatic equilibrium'),
('f1110008-0000-0000-0000-000000000005', 'a1111111-1111-1111-1111-111111111111', 'f1110008-0000-0000-0000-000000000008', 'MEDIUM', 'Capacitance of isolated sphere of radius R is:', '4piepsilon_0R', '4piepsilon_0/R', 'R/4piepsilon_0', '4piepsilon_0R^2', 'A', 'C=4piepsilon_0R (isolated sphere capacitance)'),
('f1110008-0000-0000-0000-000000000006', 'a1111111-1111-1111-1111-111111111111', 'f1110008-0000-0000-0000-000000000008', 'EASY', 'A parallel plate capacitor has plates of area A, separation d. Capacitance = :', 'epsilon_0A/d', 'epsilon_0d/A', 'epsilon_0Ad', 'epsilon_0/Ad', 'A', 'C=epsilon_0A/d for parallel plate capacitor in vacuum'),
('f1110008-0000-0000-0000-000000000008', 'a1111111-1111-1111-1111-111111111111', 'f1110008-0000-0000-0000-000000000008', 'MEDIUM', 'Gauss''s law: E dA = Q_enc/epsilon_0. Electric field at distance r outside uniformly charged sphere of total charge Q:', 'kQ/r^2', 'kQr', 'kQ/r', 'kQ^2/r^2', 'A', 'By Gauss''s law, field outside = kQ/r^2 (same as point charge)'),
